const TAMANHO_MAXIMO = 20 * 1024 * 1024;
const items = $input.all();
if (!items || !items.length) return [{ json: { valido: false, erros: ["sem itens"] } }];
const item = items[0];
let buf = null;
let fileName = "";
let mimeType = "";
let binaryKey = "";
let createdFromBase64 = false;
// 1. Check $binary first
const binKeys = Object.keys($binary || {});
if (binKeys.length > 0) {
  binaryKey = binKeys[0];
  const bin = $binary[binaryKey];
  if (bin) {
    // Method signature: getBinaryDataBuffer(itemIndex, propertyName|binaryData)
    try { buf = await this.helpers.getBinaryDataBuffer(0, bin); } catch(e) {}
    if (!buf) { try { buf = await this.helpers.getBinaryDataBuffer(0, binaryKey); } catch(e) {} }
    if (!buf && bin.data) {
      if (Buffer.isBuffer(bin.data)) buf = bin.data;
      else if (typeof bin.data === "string") buf = Buffer.from(bin.data, "base64");
    }
    fileName = bin.fileName || "";
    mimeType = bin.mimeType || "";
  }
}
// 2. Check item.binary fallback
if (!buf && item && item.binary) {
  const ibk = Object.keys(item.binary);
  if (ibk.length > 0) {
    if (!binaryKey) binaryKey = ibk[0];
    const ibKey = ibk[0];
    const ib = item.binary[ibKey];
    if (ib) {
      try { buf = await this.helpers.getBinaryDataBuffer(0, ib); } catch(e) {}
      if (!buf) { try { buf = await this.helpers.getBinaryDataBuffer(0, ibKey); } catch(e) {} }
      if (!buf && ib.data) {
        buf = Buffer.isBuffer(ib.data) ? ib.data : Buffer.from(ib.data, "base64");
      }
      fileName = fileName || ib.fileName || "";
      mimeType = mimeType || ib.mimeType || "";
    }
  }
}
// 3. Check JSON body for base64-encoded file (from Enviar para Agente Comprovante Code node)
const body = item.json.body || item.json || {};
if (!buf && body.file_base64) {
  try {
    buf = Buffer.from(body.file_base64, "base64");
    fileName = fileName || body.file_name || body.fileName || "";
    mimeType = mimeType || body.file_type || body.fileType || "application/octet-stream";
    binaryKey = binaryKey || "data";
    createdFromBase64 = true;
  } catch(e) {}
}
// Fallback name from JSON
fileName = fileName || body.fileName || body.file_name || body._file_name || "";
mimeType = mimeType || body.fileType || body.file_type || body._file_type || "";
// Validation
const ext = fileName ? fileName.toLowerCase().split(".").pop() : "";
const validExts = ["pdf", "jpg", "jpeg", "png"];
const erros = [];
if (!buf) erros.push("arquivo_binario_ausente");
if (buf && buf.length > TAMANHO_MAXIMO) erros.push("arquivo_excede_tamanho_maximo_20MB");
if (fileName && !validExts.includes(ext)) erros.push("Extensao_invalida: " + ext);
let hash = "";
let fileSize = 0;
if (buf) {
  fileSize = buf.length;
  var s = 0;
  var arr = new Uint8Array(buf.buffer || buf);
  for (var i = 0; i < arr.length; i++) { s = (s * 31 + arr[i]) >>> 0; }
  hash = s.toString(16).padStart(8, "0");
}
const caminho_completo = buf ? "/home/node/.n8n-files/comprovantes/entrada/" + Date.now() + "_" + (fileName || "arquivo") : "";
const temBinario = binKeys.length > 0 || (item && item.binary && Object.keys(item.binary).length > 0) || createdFromBase64;
const outputBinary = createdFromBase64 ? { data: { data: buf.toString("base64"), mimeType: mimeType, fileName: fileName } } : (item.binary || undefined);
if (!binaryKey && temBinario) binaryKey = "data";
return [{ json: { valido: erros.length === 0, erros: erros, arquivo_nome: fileName, arquivo_tipo: mimeType, fileSize: fileSize, hash_sha256: hash, tem_binario: temBinario, binario_key: binaryKey, caminho_completo: caminho_completo }, binary: outputBinary }];

const item = $input.first();
if (!item) return [{ json: { ocr_status: "erro", ocr_erro: "sem_item" } }];
const binKey = item.json.binario_key || "data";
const bin = $binary && $binary[binKey];
let buf = null;
if (bin) {
  try { buf = await this.helpers.getBinaryDataBuffer(0, bin); } catch(e) {}
  if (!buf && bin.data) {
    buf = Buffer.isBuffer(bin.data) ? bin.data : Buffer.from(bin.data, "base64");
  }
}
if (!buf && item.binary) {
  const ibk = Object.keys(item.binary);
  if (ibk.length > 0) {
    const ib = item.binary[ibk[0]];
    try { buf = await this.helpers.getBinaryDataBuffer(0, ib); } catch(e) {}
    if (!buf && ib.data) {
      buf = Buffer.isBuffer(ib.data) ? ib.data : Buffer.from(ib.data, "base64");
    }
  }
}
if (!buf) return [{ json: { ...item.json, ocr_status: "erro", ocr_erro: "sem_dados_binario", ocr_engine: "nenhum", ocr_texto: "", ocr_timestamp: new Date().toISOString(), ocr_path_txt: "" } }];
const mime = item.json.arquivo_tipo || "application/octet-stream";
const b64 = buf.toString("base64");
const dataUri = "data:" + mime + ";base64," + b64;
const arquivoNome = item.json.arquivo_nome || "arquivo";
const isPdf = arquivoNome.toLowerCase().endsWith(".pdf");
let ocrStatus = "erro";
let ocrTexto = "";
let ocrEngine = "nenhum";
let ocrErro = "";
// 1. Try OCR.space
const apiKey = $env.OCR_SPACE_API_KEY || "";
if (apiKey) {
  try {
    const resp = await this.helpers.httpRequest({
      method: "POST",
      url: "https://api.ocr.space/v2/parse/image",
      headers: { "Content-Type": "application/json" },
      body: {
        apikey: apiKey,
        base64Image: dataUri,
        language: "por",
        isOverlayRequired: false,
        OCREngine: 2
      },
      timeout: 30000
    });
    if (resp.OCRExitCode === 1 && resp.ParsedResults && resp.ParsedResults.length > 0) {
      var text = (resp.ParsedResults[0].ParsedText || "").trim();
      if (text) {
        ocrStatus = "ok"; ocrTexto = text; ocrEngine = "ocr.space";
      }
    }
    if (ocrStatus !== "ok") {
      ocrErro = (resp.ParsedResults && resp.ParsedResults[0] && resp.ParsedResults[0].ErrorMessage) || "OCR.space_falhou_sem_texto";
    }
  } catch (e) {
    ocrErro = "OCR.space_erro: " + (e.message || String(e)).substring(0, 100);
  }
}
// 2. Fallback: Tesseract
if (ocrStatus !== "ok") {
  if (isPdf) {
    ocrErro = "PDF_NAO_SUPORTADO_POR_TESSERACT";
  } else {
    try {
      const resp = await this.helpers.httpRequest({
        method: "POST",
        url: "http://ocr-service:3002/ocr",
        headers: { "Content-Type": "application/json" },
        body: { base64Image: dataUri },
        timeout: 30000
      });
      if (resp.text) {
        ocrStatus = "ok"; ocrTexto = resp.text; ocrEngine = "tesseract";
      } else {
        ocrErro = "Tesseract: " + (resp.error || "sem_texto");
      }
    } catch (e) {
      ocrErro = "Tesseract_erro: " + (e.message || String(e)).substring(0, 100);
    }
  }
}
// 3. Create .txt binary output
const txtFileName = arquivoNome.replace(/\.[^.]+$/, "") + ".txt";
const txtContent = "=== OCR RESULT ===\nEngine: " + ocrEngine + "\nStatus: " + ocrStatus + "\nTimestamp: " + new Date().toISOString() + "\n\n" + ocrTexto;
const txtB64 = Buffer.from(txtContent, "utf-8").toString("base64");
const ocrPathTxt = "/home/node/.n8n-files/comprovantes/processados/" + txtFileName;
return [{
  json: {
    ...item.json,
    ocr_status: ocrStatus,
    ocr_texto: ocrTexto,
    ocr_engine: ocrEngine,
    ocr_erro: ocrErro,
    ocr_timestamp: new Date().toISOString(),
    ocr_path_txt: ocrPathTxt,
    ocr_txt_nome: txtFileName
  },
  binary: {
    "ocr_resultado": {
      data: txtB64,
      mimeType: "text/plain",
      fileName: txtFileName
    }
  }
}];
